mapper.select:
SELECT calib_id, equip_type, equip_name, zone_location, meas_location,
       attach_file, last_calib_dt, next_calib_dt,
       std_temp, meas_temp, deviation, judgment, status,
       handler, remark, reg_dt, upd_dt
FROM tb_calib_thermocouple
WHERE del_yn = 'N'

    AND equip_type = #{equipType}


    AND status = #{status}


    AND (equip_name LIKE #{keyword}
      OR zone_location LIKE #{keyword}
      OR meas_location LIKE #{keyword}
      OR handler LIKE #{keyword})

ORDER BY calib_id DESC

mapper.update:
UPDATE tb_calib_thermocouple
SET attach_file = #{attachFile}, upd_dt = CURRENT_TIMESTAMP
WHERE calib_id = #{calibId}

UPDATE tb_calib_thermocouple
SET del_yn = 'Y', upd_dt = CURRENT_TIMESTAMP
WHERE calib_id = #{calibId}
